'use client';

import React, { useState, useEffect } from 'react';
import { X, Calendar, MapPin, User, Save, Clock, Ruler } from 'lucide-react';
import { toast } from 'sonner';
import { addDatSession } from '@/src/services/datService';
import ViDateInput from '@/src/components/shared/ViDateInput';

interface AddDatModalProps {
  isOpen: boolean;
  onClose: () => void;
  studentName?: string;
  enrollmentId?: string;
  onSuccess?: () => void;
}

interface DatFormData {
  date: string;
  timeStart: string;
  timeEnd: string;
  duration: string;
  distance: string;
  note: string;
}

const initialState: DatFormData = {
  date: new Date().toISOString().split('T')[0],
  timeStart: '',
  timeEnd: '',
  duration: '',
  distance: '',
  note: '',
};

const FieldWrapper = ({
  label,
  required,
  children,
  field,
  touched,
  errors,
  icon: Icon,
}: {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  field: string;
  touched: Record<string, boolean>;
  errors: Record<string, string>;
  icon?: any;
}) => {
  const hasError = touched[field] && errors[field];
  return (
    <div className="flex flex-col gap-1.5">
      <label
        className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 transition-colors ${hasError ? 'text-rose-500' : 'text-gray-400'}`}
      >
        {Icon && <Icon className="w-3.5 h-3.5 text-indigo-500" />}
        {label} {required && <span className="text-rose-500">*</span>}
      </label>
      <div className="relative group">{children}</div>
      {hasError && (
        <p className="text-[10px] font-bold text-rose-500 mt-1 ml-1 animate-in fade-in slide-in-from-top-1">
          {errors[field]}
        </p>
      )}
    </div>
  );
};

export default function AddDatModal({ isOpen, onClose, studentName = '', enrollmentId, onSuccess }: AddDatModalProps) {
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState<DatFormData>({ ...initialState });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  useEffect(() => {
    if (isOpen) {
      setForm({ ...initialState, date: new Date().toISOString().split('T')[0] });
      setErrors({});
      setTouched({});
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const validate = (data = form) => {
    const errs: Record<string, string> = {};
    if (!data.date) errs.date = 'Vui lòng chọn ngày học.';

    if (!data.timeStart) errs.timeStart = 'Vui lòng nhập giờ bắt đầu.';
    if (!data.timeEnd) errs.timeEnd = 'Vui lòng nhập giờ kết thúc.';

    if (!data.duration.trim()) errs.duration = 'Vui lòng nhập thời lượng.';
    else if (isNaN(parseInt(data.duration)) || parseInt(data.duration) <= 0) {
      errs.duration = 'Thời lượng phải là số dương.';
    }

    if (!data.distance.trim()) errs.distance = 'Vui lòng nhập quãng đường.';
    else if (isNaN(parseFloat(data.distance)) || parseFloat(data.distance) <= 0) {
      errs.distance = 'Quãng đường phải là số dương.';
    }

    if (data.timeStart && data.timeEnd) {
      const [sh, sm] = data.timeStart.split(':').map(Number);
      const [eh, em] = data.timeEnd.split(':').map(Number);
      const diffMinutes = eh * 60 + em - (sh * 60 + sm);

      if (diffMinutes <= 0) {
        errs.timeEnd = 'Thời gian kết thúc phải sau thời gian bắt đầu.';
      } else if (!errs.duration && parseInt(data.duration) > diffMinutes) {
        errs.duration = 'Thời lượng không được lớn hơn khoảng thời gian từ bắt đầu đến kết thúc.';
      }
    }

    setErrors(errs);
    return errs;
  };

  const handleChange = (field: string, value: string) => {
    const updated = { ...form, [field]: value };
    setForm(updated);
    if (touched[field]) {
      validate(updated);
    }
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    validate();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!enrollmentId) {
      toast.error('Không tìm thấy thông tin đăng ký của học viên.');
      return;
    }

    const allTouched = { date: true, duration: true, distance: true, timeStart: true, timeEnd: true };
    setTouched(allTouched);

    const errs = validate();
    if (Object.keys(errs).length > 0) {
      toast.error('Vui lòng kiểm tra lại thông tin buổi DAT');
      return;
    }

    setLoading(true);
    try {
      const start = new Date(`${form.date}T${form.timeStart}:00`);
      const end = new Date(`${form.date}T${form.timeEnd}:00`);

      if (end <= start) {
        toast.error('Thời gian kết thúc phải sau thời gian bắt đầu.');
        setLoading(false);
        return;
      }

      const res = await addDatSession({
        course_student_id: enrollmentId,
        session_type: 'dat',
        start_time: start.toISOString(),
        end_time: end.toISOString(),
        distance_km: parseFloat(form.distance),
        notes: form.note,
      });

      if (res.success) {
        toast.success(`Đã lưu thành công buổi DAT ${form.distance}km cho ${studentName}!`);
        onSuccess?.();
        onClose();
      } else {
        toast.error(res.message || 'Lỗi khi lưu dữ liệu DAT.');
      }
    } catch (error) {
      toast.error('Lỗi khi kết nối đến máy chủ.');
    } finally {
      setLoading(false);
    }
  };

  const getInputClass = (field: string) => {
    const base =
      'w-full px-4 py-2.5 bg-white border rounded-xl focus:outline-none focus:ring-4 transition-all text-sm font-medium';
    if (touched[field] && errors[field]) {
      return `${base} border-rose-300 bg-rose-50/20 text-rose-900 focus:ring-rose-500/10 focus:border-rose-500`;
    }
    return `${base} border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500`;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="bg-white/95 backdrop-blur-xl rounded-[2rem] w-full max-w-md shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
        {/* Header */}
        <div className="px-8 py-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <div>
            <h2 className="text-xl font-black text-gray-900 tracking-tight">THÊM BUỔI DAT</h2>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">
              Ghi nhận tiến độ đào tạo DAT
            </p>
          </div>
          <button
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-rose-500 hover:bg-rose-50 rounded-full transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Body */}
        <div className="p-8">
          <form id="add-dat-form" onSubmit={handleSubmit} className="flex flex-col gap-6" noValidate>
            {/* Student info tag */}
            <div className="px-5 py-3 bg-indigo-50/50 border border-indigo-100 text-indigo-800 rounded-2xl flex items-center gap-3 font-extrabold text-sm shadow-sm ring-1 ring-indigo-500/10">
              <User className="w-4 h-4 text-indigo-500 shrink-0" />
              <span className="truncate">{studentName}</span>
            </div>

            <FieldWrapper label="NGÀY HỌC" required field="date" touched={touched} errors={errors} icon={Calendar}>
              <ViDateInput
                className={getInputClass('date')}
                value={form.date}
                onChange={(val) => handleChange('date', val)}
              />
            </FieldWrapper>

            <div className="grid grid-cols-2 gap-4">
              <FieldWrapper label="GIỜ BẮT ĐẦU" required field="timeStart" touched={touched} errors={errors} icon={Clock}>
                <input
                  type="time"
                  className={getInputClass('timeStart')}
                  value={form.timeStart}
                  onChange={(e) => handleChange('timeStart', e.target.value)}
                  onBlur={() => handleBlur('timeStart')}
                />
              </FieldWrapper>

              <FieldWrapper label="GIỜ KẾT THÚC" required field="timeEnd" touched={touched} errors={errors} icon={Clock}>
                <input
                  type="time"
                  className={getInputClass('timeEnd')}
                  value={form.timeEnd}
                  onChange={(e) => handleChange('timeEnd', e.target.value)}
                  onBlur={() => handleBlur('timeEnd')}
                />
              </FieldWrapper>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <FieldWrapper
                label="THỜI LƯỢNG (PHÚT)"
                required
                field="duration"
                touched={touched}
                errors={errors}
                icon={Clock}
              >
                <div className="relative">
                  <input
                    type="text"
                    placeholder="VD: 180"
                    className={getInputClass('duration')}
                    value={form.duration}
                    onChange={(e) => handleChange('duration', e.target.value)}
                    onBlur={() => handleBlur('duration')}
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-gray-400 uppercase tracking-tight">
                    phút
                  </span>
                </div>
              </FieldWrapper>

              <FieldWrapper
                label="QUÃNG ĐƯỜNG (KM)"
                required
                field="distance"
                touched={touched}
                errors={errors}
                icon={Ruler}
              >
                <div className="relative">
                  <input
                    type="text"
                    placeholder="VD: 84.5"
                    className={getInputClass('distance')}
                    value={form.distance}
                    onChange={(e) => handleChange('distance', e.target.value)}
                    onBlur={() => handleBlur('distance')}
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-gray-400 uppercase tracking-tight">
                    km
                  </span>
                </div>
              </FieldWrapper>
            </div>

            <FieldWrapper label="GHI CHÚ" field="note" touched={touched} errors={errors} icon={MapPin}>
              <input
                type="text"
                placeholder="Tuyến đường, giáo viên, xe tập..."
                className={getInputClass('note')}
                value={form.note}
                onChange={(e) => handleChange('note', e.target.value)}
              />
            </FieldWrapper>
          </form>
        </div>

        {/* Footer */}
        <div className="px-8 py-6 flex justify-end gap-3 rounded-b-2xl border-t border-gray-100 bg-gray-50/50">
          <button
            type="button"
            onClick={onClose}
            className="px-6 py-3 text-xs font-black uppercase tracking-widest text-gray-500 hover:text-gray-900 hover:bg-gray-200/50 rounded-2xl transition-all"
          >
            Hủy bỏ
          </button>
          <button
            type="submit"
            form="add-dat-form"
            disabled={loading}
            className="px-8 py-3 text-xs font-black uppercase tracking-widest text-white bg-indigo-600 hover:bg-indigo-700 rounded-2xl transition-all shadow-xl shadow-indigo-600/20 active:scale-95 flex items-center gap-2.5 disabled:opacity-50"
          >
            {loading ? (
              <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              <Save className="w-4 h-4" />
            )}
            Lưu dữ liệu
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import ViDateInput from '@/src/components/shared/ViDateInput';
import { X, Calendar, MapPin, Save, Clock, Ruler } from 'lucide-react';
import { toast } from 'sonner';
import { addDatSession } from '@/src/services/datService';

interface DatSessionModalProps {
  isOpen: boolean;
  onClose: () => void;
  enrollmentId: string;
  onSuccess: () => void;
}

interface DatFormData {
  date: string;
  timeStart: string;
  timeEnd: string;
  duration: string;
  distance: string;
  note: string;
}

const initialState: DatFormData = {
  date: new Date().toISOString().split('T')[0],
  timeStart: '',
  timeEnd: '',
  duration: '',
  distance: '',
  note: '',
};

const syncDuration = (startStr: string, endStr: string) => {
  if (!startStr || !endStr) return '';
  try {
    const [sh, sm] = startStr.split(':').map(Number);
    const [eh, em] = endStr.split(':').map(Number);
    const diffMinutes = eh * 60 + em - (sh * 60 + sm);
    return diffMinutes > 0 ? diffMinutes.toString() : '';
  } catch {
    return '';
  }
};

const syncEndTime = (startStr: string, durationStr: string) => {
  if (!startStr || !durationStr || isNaN(parseInt(durationStr))) return '';
  try {
    const [sh, sm] = startStr.split(':').map(Number);
    const totalMinutes = sh * 60 + sm + parseInt(durationStr || '0');
    const eh = Math.floor(totalMinutes / 60) % 24;
    const em = totalMinutes % 60;
    return `${eh.toString().padStart(2, '0')}:${em.toString().padStart(2, '0')}`;
  } catch {
    return '';
  }
};

const FieldWrapper = ({
  label,
  required,
  children,
  field,
  touched,
  errors,
  icon: Icon,
}: {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  field: string;
  touched: Record<string, boolean>;
  errors: Record<string, string>;
  icon?: any;
}) => {
  const hasError = touched[field] && errors[field];
  return (
    <div className="flex flex-col gap-1.5">
      <label
        className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 transition-colors ${hasError ? 'text-rose-500' : 'text-gray-400'}`}
      >
        {Icon && <Icon className="w-3.5 h-3.5 text-indigo-500" />}
        {label} {required && <span className="text-rose-500">*</span>}
      </label>
      <div className="relative group">{children}</div>
      {hasError && (
        <p className="text-[10px] font-bold text-rose-500 mt-1 ml-1 animate-in fade-in slide-in-from-top-1">
          {errors[field]}
        </p>
      )}
    </div>
  );
};

const DatSessionModal: React.FC<DatSessionModalProps> = ({ isOpen, onClose, enrollmentId, onSuccess }) => {
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState<DatFormData>({ ...initialState });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  useEffect(() => {
    if (isOpen) {
      setForm({ ...initialState, date: new Date().toISOString().split('T')[0] });
      setErrors({});
      setTouched({});
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const validate = (data = form) => {
    const errs: Record<string, string> = {};

    if (!data.date) errs.date = 'Vui lòng chọn ngày học.';
    if (!data.timeStart) errs.timeStart = 'Vui lòng nhập giờ bắt đầu.';
    if (!data.timeEnd) errs.timeEnd = 'Vui lòng nhập giờ kết thúc.';

    if (!data.duration.trim()) errs.duration = 'Vui lòng nhập thời lượng.';
    else if (isNaN(parseInt(data.duration)) || parseInt(data.duration) <= 0) {
      errs.duration = 'Thời lượng phải là số dương.';
    }

    if (!data.distance.trim()) errs.distance = 'Vui lòng nhập quãng đường.';
    else if (isNaN(parseFloat(data.distance)) || parseFloat(data.distance) <= 0) {
      errs.distance = 'Quãng đường phải là số dương.';
    }

    setErrors(errs);
    return errs;
  };

  const handleChange = (field: keyof DatFormData, value: string) => {
    setForm((prev) => {
      const updated = { ...prev, [field]: value };

      if (field === 'timeStart') {
        if (updated.timeEnd) {
          updated.duration = syncDuration(value, updated.timeEnd);
        } else if (updated.duration) {
          updated.timeEnd = syncEndTime(value, updated.duration);
        }
      }

      if (field === 'timeEnd') {
        updated.duration = syncDuration(updated.timeStart, value);
      }

      if (field === 'duration') {
        updated.timeEnd = syncEndTime(updated.timeStart, value);
      }

      if (touched[field]) {
        validate(updated);
      }

      return updated;
    });
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    validate();
  };

  const getInputClass = (field: string) => {
    const base =
      'w-full px-4 py-2.5 bg-white border rounded-xl focus:outline-none focus:ring-4 transition-all text-sm font-medium';
    if (touched[field] && errors[field]) {
      return `${base} border-rose-300 bg-rose-50/20 text-rose-900 focus:ring-rose-500/10 focus:border-rose-500`;
    }
    return `${base} border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500`;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!enrollmentId) {
      toast.error('Không tìm thấy thông tin đăng ký của học viên.');
      return;
    }

    const allTouched = { date: true, duration: true, distance: true, timeStart: true, timeEnd: true };
    setTouched(allTouched);

    const errs = validate();
    if (Object.keys(errs).length > 0) {
      toast.error('Vui lòng kiểm tra lại thông tin buổi DAT');
      return;
    }

    setLoading(true);
    try {
      const start = new Date(`${form.date}T${form.timeStart}:00`);
      const end = new Date(`${form.date}T${form.timeEnd}:00`);

      if (end <= start) {
        toast.error('Thời gian kết thúc phải sau thời gian bắt đầu.');
        setLoading(false);
        return;
      }

      const res = await addDatSession({
        course_student_id: enrollmentId,
        session_type: 'dat',
        start_time: start.toISOString(),
        end_time: end.toISOString(),
        distance_km: parseFloat(form.distance),
        notes: form.note,
      });

      if (res.success) {
        toast.success('Đã lưu thành công buổi DAT!');
        onSuccess();
        onClose();
      } else {
        toast.error(res.message || 'Lỗi khi lưu dữ liệu DAT.');
      }
    } catch (error) {
      toast.error('Lỗi khi kết nối đến máy chủ.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="bg-white/95 backdrop-blur-xl rounded-[2rem] w-full max-w-md shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
        <div className="px-8 py-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <div>
            <h2 className="text-xl font-black text-gray-900 tracking-tight">THÊM BUỔI DAT</h2>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">
              Ghi nhận tiến độ đào tạo DAT
            </p>
          </div>
          <button
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-rose-500 hover:bg-rose-50 rounded-full transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-8">
          <form id="student-detail-dat-form" onSubmit={handleSubmit} className="flex flex-col gap-6" noValidate>
            <FieldWrapper label="NGÀY HỌC" required field="date" touched={touched} errors={errors} icon={Calendar}>
              <ViDateInput
                className={getInputClass('date')}
                value={form.date}
                onChange={(val) => handleChange('date', val)}
              />
            </FieldWrapper>

            <div className="grid grid-cols-2 gap-4">
              <FieldWrapper label="GIỜ BẮT ĐẦU" required field="timeStart" touched={touched} errors={errors} icon={Clock}>
                <input
                  type="time"
                  className={getInputClass('timeStart')}
                  value={form.timeStart}
                  onChange={(e) => handleChange('timeStart', e.target.value)}
                  onBlur={() => handleBlur('timeStart')}
                />
              </FieldWrapper>

              <FieldWrapper label="GIỜ KẾT THÚC" required field="timeEnd" touched={touched} errors={errors} icon={Clock}>
                <input
                  type="time"
                  className={getInputClass('timeEnd')}
                  value={form.timeEnd}
                  onChange={(e) => handleChange('timeEnd', e.target.value)}
                  onBlur={() => handleBlur('timeEnd')}
                />
              </FieldWrapper>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <FieldWrapper
                label="THỜI LƯỢNG (PHÚT)"
                required
                field="duration"
                touched={touched}
                errors={errors}
                icon={Clock}
              >
                <div className="relative">
                  <input
                    type="text"
                    placeholder="VD: 180"
                    className={getInputClass('duration')}
                    value={form.duration}
                    onChange={(e) => handleChange('duration', e.target.value)}
                    onBlur={() => handleBlur('duration')}
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-gray-400 uppercase tracking-tight">
                    phút
                  </span>
                </div>
              </FieldWrapper>

              <FieldWrapper
                label="QUÃNG ĐƯỜNG (KM)"
                required
                field="distance"
                touched={touched}
                errors={errors}
                icon={Ruler}
              >
                <div className="relative">
                  <input
                    type="text"
                    placeholder="VD: 84.5"
                    className={getInputClass('distance')}
                    value={form.distance}
                    onChange={(e) => handleChange('distance', e.target.value)}
                    onBlur={() => handleBlur('distance')}
                  />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-gray-400 uppercase tracking-tight">
                    km
                  </span>
                </div>
              </FieldWrapper>
            </div>

            <FieldWrapper label="GHI CHÚ" field="note" touched={touched} errors={errors} icon={MapPin}>
              <input
                type="text"
                placeholder="Tuyến đường, giáo viên, xe tập..."
                className={getInputClass('note')}
                value={form.note}
                onChange={(e) => handleChange('note', e.target.value)}
              />
            </FieldWrapper>
          </form>
        </div>

        <div className="px-8 py-6 flex justify-end gap-3 rounded-b-2xl border-t border-gray-100 bg-gray-50/50">
          <button
            type="button"
            onClick={onClose}
            className="px-6 py-3 text-xs font-black uppercase tracking-widest text-gray-500 hover:text-gray-900 hover:bg-gray-200/50 rounded-2xl transition-all"
          >
            Hủy bỏ
          </button>
          <button
            type="submit"
            form="student-detail-dat-form"
            disabled={loading}
            className="px-8 py-3 text-xs font-black uppercase tracking-widest text-white bg-indigo-600 hover:bg-indigo-700 rounded-2xl transition-all shadow-xl shadow-indigo-600/20 active:scale-95 flex items-center gap-2.5 disabled:opacity-50"
          >
            {loading ? (
              <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              <Save className="w-4 h-4" />
            )}
            Lưu dữ liệu
          </button>
        </div>
      </div>
    </div>
  );
};

export default DatSessionModal;

'use client';

import React, { useState, useEffect } from 'react';
import {
  BarChart3,
  TrendingUp,
  Search,
  Filter,
  PlayCircle,
  Trophy,
  User,
  Plus,
  CheckCircle2,
  ChevronRight,
  CheckSquare,
  AlertCircle,
  Clock,
} from 'lucide-react';
import StatCard from '@/src/components/ui/StatCard';
import AddDatModal from '@/src/components/progress/AddDatModal';
import StudentDetailDrawer from '@/src/components/students/StudentDetailDrawer';
import Skeleton from '@/src/components/shared/Skeleton';
import { apiClient } from '@/src/services/api';
import dynamic from 'next/dynamic';

const Line = dynamic(() => import('react-chartjs-2').then((mod) => mod.Line), {
  ssr: false,
  loading: () => (
    <div className="h-[300px] w-full bg-gray-50/50 animate-pulse rounded-2xl border border-dashed border-gray-200 flex items-center justify-center text-[10px] font-bold text-gray-400">
      Đang tải biểu đồ tiến độ...
    </div>
  ),
});

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title as ChartTitle,
  Tooltip,
  Legend,
  Filler,
} from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, ChartTitle, Tooltip, Legend, Filler);

export default function ProgressPage() {
  const [isDatModalOpen, setIsDatModalOpen] = useState(false);
  const [isDetailDrawerOpen, setIsDetailDrawerOpen] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [selectedStudentObj, setSelectedStudentObj] = useState<any>(null);
  const [students, setStudents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterFlags, setFilterFlags] = useState({ theory: false, cabin: false, sand: false });
  const [analytics, setAnalytics] = useState<any>(null);

  // --- Skeleton Loading States ---
  const StatsSkeleton = () => (
    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 animate-fade-in">
      {[1, 2, 3, 4].map((i) => (
        <Skeleton key={i} variant="rect" height={100} />
      ))}
    </div>
  );

  const TableSkeleton = () => (
    <div className="bg-white border border-gray-100 shadow-card rounded-card overflow-hidden animate-fade-in">
      <div className="p-6 border-b border-gray-100 flex justify-between items-center">
        <Skeleton variant="rect" width={180} height={20} />
      </div>
      <div className="px-6 py-4 space-y-4">
        {[1, 2, 3, 4, 5, 6].map((i) => (
          <div key={i} className="flex gap-4 items-center">
            <Skeleton variant="rect" width="30%" height={16} />
            <Skeleton variant="rect" width="15%" height={16} />
            <Skeleton variant="rect" width="15%" height={16} />
            <Skeleton variant="rect" width="15%" height={16} />
            <Skeleton variant="rect" width="25%" height={16} />
          </div>
        ))}
      </div>
    </div>
  );

  const fetchStudents = async () => {
    setLoading(true);
    try {
      let url = `/students?limit=25&search=${searchTerm}`;
      if (filterFlags.theory) url += `&theory=true`;
      if (filterFlags.cabin) url += `&cabin=true`;
      if (filterFlags.sand) url += `&sand=true`;

      const res = await apiClient(url);
      const list = res.data?.docs || res.data?.data || (Array.isArray(res.data) ? res.data : []);
      setStudents(list);
    } catch (error) {
      console.error('Failed to fetch students:', error);
      setStudents([]);
    } finally {
      setLoading(false);
    }
  };

  const fetchAnalytics = async () => {
    try {
      const res = await apiClient('/dat/analytics');
      if (res.success) {
        setAnalytics(res.data);
      }
    } catch (error) {
      console.error('Failed to fetch DAT analytics:', error);
    }
  };

  useEffect(() => {
    let cancelled = false;
    fetchAnalytics();
    return () => { cancelled = true; };
  }, []);

  const handleRefresh = async () => {
    await Promise.all([fetchStudents(), fetchAnalytics()]);
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchStudents();
    }, 500);
    return () => clearTimeout(timer);
  }, [searchTerm, filterFlags]);

  const chartData = {
    labels: analytics?.monthly_growth?.map((item: any) => item.label) || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        fill: true,
        label: 'Tổng Km DAT (toàn cơ sở)',
        data: analytics?.monthly_growth?.map((item: any) => item.value) || [0, 0, 0, 0, 0, 0],
        borderColor: '#6366f1',
        backgroundColor: 'rgba(99, 102, 241, 0.1)',
        tension: 0.4,
      },
    ],
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-2 duration-700">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight leading-tight">
            Theo Dõi Tiến Độ
          </h2>
          <p className="text-gray-500 font-medium mt-1">Phân tích tiến độ học tập và thiết bị DAT</p>
        </div>
      </div>

      {/* Stats Grid */}
      {!analytics ? (
        <StatsSkeleton />
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 animate-fade-in">
          <StatCard
            label="Học viên đang học"
            value={(analytics?.global_stats?.active_students || 0).toString()}
            icon={<PlayCircle className="w-5 h-5" />}
            color="primary"
          />
          <StatCard
            label="Hoàn thành đủ Km"
            value={(analytics?.global_stats?.completed_km_count || 0).toString()}
            icon={<Trophy className="w-5 h-5" />}
            color="success"
          />
          <StatCard
            label="Tỷ lệ đậu sát hạch"
            value={`${analytics?.global_stats?.pass_rate || 0}%`}
            icon={<TrendingUp className="w-5 h-5" />}
            color="indigo"
          />
          <StatCard
            label="Tổng số học viên"
            value={(analytics?.global_stats?.total_students || 0).toString()}
            icon={<User className="w-5 h-5" />}
            color="indigo"
          />
        </div>
      )}

      {/* Growth Chart */}
      <div className="bg-white p-6 rounded-card shadow-card border border-gray-100 flex flex-col gap-6">
        <div className="flex items-center gap-2 mb-2">
          <BarChart3 className="w-5 h-5 text-indigo-500" />
          <h3 className="font-extrabold text-gray-800">Biểu đồ tăng trưởng Km DAT (Tháng này)</h3>
        </div>
        <div className="h-[300px]">
          <Line
            data={chartData}
            options={{
              maintainAspectRatio: false,
              plugins: { legend: { position: 'top' } },
              scales: {
                y: { beginAtZero: true, grid: { color: 'rgba(0,0,0,0.05)' } },
                x: { grid: { display: false } },
              },
            }}
          />
        </div>
      </div>

      {/* Toolbar */}
      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mt-2">
        <h3 className="font-extrabold text-gray-800 flex items-center gap-2 whitespace-nowrap">
          <User className="w-5 h-5 text-primary" /> Tiến độ cá nhân
        </h3>
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Tìm tên học viên..."
              className="w-full pl-9 pr-4 py-1.5 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex flex-wrap gap-2 items-center w-full sm:w-auto mt-2 sm:mt-0">
            <span className="text-[10px] uppercase font-black tracking-widest text-gray-400 mr-1 shrink-0">
              Bộ lọc hoàn thành:
            </span>
            <button
              onClick={() => setFilterFlags((prev) => ({ ...prev, theory: !prev.theory }))}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all border shrink-0 ${filterFlags.theory ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
            >
              Lý thuyết
            </button>
            <button
              onClick={() => setFilterFlags((prev) => ({ ...prev, cabin: !prev.cabin }))}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all border shrink-0 ${filterFlags.cabin ? 'bg-amber-500 text-white border-amber-500 shadow-sm' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
            >
              Cabin
            </button>
            <button
              onClick={() => setFilterFlags((prev) => ({ ...prev, sand: !prev.sand }))}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all border shrink-0 ${filterFlags.sand ? 'bg-emerald-500 text-white border-emerald-500 shadow-sm' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
            >
              Sa hình
            </button>
          </div>
        </div>
      </div>

      {/* Students Table */}
      <div className="bg-white border border-gray-100 shadow-card rounded-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50/70 border-b border-gray-100 text-[11px] uppercase tracking-wider text-gray-500 font-extrabold">
                <th className="px-6 py-4">Học viên</th>
                <th className="px-6 py-4">Lý thuyết</th>
                <th className="px-6 py-4">Cabin</th>
                <th className="px-6 py-4">Sa hình</th>
                <th className="px-6 py-4 min-w-[200px]">DAT (km/h)</th>
                <th className="px-6 py-4 text-center">Tốt nghiệp</th>
                <th className="px-6 py-4 text-right">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {loading ? (
                Array.from({ length: 6 }).map((_, i) => (
                  <tr key={i}>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width="60%" />
                    </td>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width={80} />
                    </td>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width={80} />
                    </td>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width={80} />
                    </td>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width="70%" />
                    </td>
                    <td className="px-6 py-4">
                      <Skeleton variant="rect" height={20} width={90} />
                    </td>
                    <td className="px-6 py-4 text-right">
                      <Skeleton variant="rect" height={32} width={100} className="inline-block" />
                    </td>
                  </tr>
                ))
              ) : students.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-20 text-center text-gray-400 font-medium">
                    Không tìm thấy học viên nào.
                  </td>
                </tr>
              ) : (
                students.map((item, idx) => {
                  const theoryStatus = item.progress_flags?.theory_completed ? 'done' : 'waiting';
                  const cabinStatus = item.progress_flags?.cabin_completed ? 'done' : 'waiting';
                  const sahinhStatus = item.progress_flags?.sand_yard_completed ? 'done' : 'waiting';
                  const km = item.dat_stats?.total_km || 0;
                  const requiredKm = parseInt(item.license_category_dat) || 840;
                  const displayKm = Math.min(km, requiredKm);
                  const datMins = item.dat_stats?.total_minutes || 0;
                  const datOk = km >= requiredKm && datMins >= 480;
                  const isEligible =
                    item.progress_flags?.graduation_eligible ||
                    (item.progress_flags?.theory_completed &&
                      item.progress_flags?.cabin_completed &&
                      item.progress_flags?.sand_yard_completed &&
                      item.progress_flags?.simulation_completed &&
                      datOk);
                  const gradStatus = isEligible ? 'passed' : 'pending';

                  const renderStatus = (status: string) => {
                    if (status === 'done')
                      return (
                        <div className="flex items-center gap-1.5 text-emerald-600">
                          <CheckCircle2 className="w-4 h-4" /> <span className="font-bold text-[11px]">Hoàn thành</span>
                        </div>
                      );
                    if (status === 'learning')
                      return (
                        <div className="flex items-center gap-1.5 text-indigo-600">
                          <PlayCircle className="w-4 h-4" /> <span className="font-bold text-[11px]">Đang học</span>
                        </div>
                      );
                    return <div className="text-gray-400 font-medium text-[11px]">- Chưa học -</div>;
                  };

                  const fullName = `${item.user_id?.last_name || ''} ${item.user_id?.first_name || ''}`;

                  return (
                    <tr key={`${item._id}-${idx}`} className="hover:bg-indigo-50/20 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                          <span
                            onClick={() => {
                              setSelectedStudentObj({
                                id: item._id,
                                name: fullName,
                                phone: item.user_id?.phone || 'Chưa cập nhật',
                                rank: item.license_category_name || item.license_category_id || 'N/A',
                                region: item.region_id?.name || 'Chưa phân bổ',
                                status: item.status_detail || 'Đang học',
                              });
                              setIsDetailDrawerOpen(true);
                            }}
                            className="font-extrabold text-sm text-indigo-700 hover:underline transition-colors cursor-pointer"
                          >
                            {fullName}
                          </span>
                          <div className="flex flex-wrap items-center gap-2 mt-1">
                            <span className="px-1.5 py-0.5 rounded bg-blue-50 text-blue-700 text-[10px] font-black border border-blue-100">
                              {item.license_category_name || item.license_category_id || 'N/A'}
                            </span>
                            <span className="text-[10px] text-gray-400 font-medium">{item.user_id?.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">{renderStatus(theoryStatus)}</td>
                      <td className="px-6 py-4">{renderStatus(cabinStatus)}</td>
                      <td className="px-6 py-4">{renderStatus(sahinhStatus)}</td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col gap-2">
                          <div className="flex items-center gap-3">
                            <span className="text-xs font-bold text-gray-600 w-14">
                              {displayKm.toFixed(1)} <span className="font-medium text-[10px]">km</span>
                            </span>
                            <div className="flex-1 max-w-[120px] h-2.5 bg-gray-100 rounded-full overflow-hidden border border-gray-200">
                              <div
                                className={`h-full rounded-full ${km >= requiredKm ? 'bg-emerald-500' : 'bg-primary'}`}
                                style={{ width: `${Math.min(100, (km / requiredKm) * 100)}%` }}
                              ></div>
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span
                          className={`px-2 py-1 rounded-lg text-[10px] uppercase font-bold border ${
                            gradStatus === 'passed'
                              ? 'bg-emerald-50 text-emerald-600 border-emerald-200'
                              : 'bg-rose-50 text-rose-500 border-rose-200'
                          }`}
                        >
                          {gradStatus === 'passed' ? 'Đủ điều kiện' : 'Chưa đủ ĐK'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex flex-col items-end gap-1.5">
                          <button
                            type="button"
                            onClick={() => {
                              if (!(item.enrollment_id || item.enrollment?._id)) return;
                              setSelectedStudent(fullName);
                              setSelectedStudentObj(item);
                              setIsDatModalOpen(true);
                            }}
                            disabled={!(item.enrollment_id || item.enrollment?._id)}
                            title={!(item.enrollment_id || item.enrollment?._id) ? 'Học viên chưa vào khóa, không thể thêm buổi DAT.' : 'Thêm buổi DAT'}
                            className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg font-bold text-[11px] shadow-sm active:scale-95 transition-colors ${
                              item.enrollment_id || item.enrollment?._id
                                ? 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-600/25'
                                : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
                            }`}
                          >
                            <Plus className="w-3.5 h-3.5" /> Thêm DAT
                          </button>
                          {!(item.enrollment_id || item.enrollment?._id) && (
                            <span className="text-[10px] text-amber-600 font-medium italic">
                              Chưa vào khóa
                            </span>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <AddDatModal
        isOpen={isDatModalOpen}
        onClose={() => setIsDatModalOpen(false)}
        studentName={selectedStudent}
        enrollmentId={selectedStudentObj?.enrollment_id || selectedStudentObj?.enrollment?._id}
        onSuccess={handleRefresh}
      />

      <StudentDetailDrawer
        isOpen={isDetailDrawerOpen}
        onClose={() => setIsDetailDrawerOpen(false)}
        student={selectedStudentObj}
        defaultTab="tiendo"
        onRefresh={handleRefresh}
      />
    </div>
  );
}

import { apiClient } from './api';

export interface DatSession {
  _id?: string;
  course_student_id: string;
  session_type: 'cabin' | 'dat';
  start_time: string;
  end_time: string;
  distance_km: number;
  notes?: string;
  created_at?: string;
}

export const addDatSession = (data: Partial<DatSession>) => {
  return apiClient('/dat', {
    method: 'POST',
    body: JSON.stringify(data),
  });
};

export const getStudentDatSessions = (enrollmentId: string) => {
  return apiClient(`/dat/student/${enrollmentId}`);
};

