import { apiClient } from './api';

export const getStudents = (page = 1, limit = 10, filters = {}) => {
  const queryParams = new URLSearchParams({
    page: page.toString(),
    limit: limit.toString(),
    ...Object.fromEntries(Object.entries(filters).filter(([_, v]) => v != null && v !== '')),
  });
  return apiClient(`/students?${queryParams.toString()}`);
};

export const getStudentById = (id: string) => apiClient(`/students/${id}`);

export const getCities = () => apiClient('/cities');

export const getLicenseCategories = () => apiClient('/students/license-categories');
export const getLeads = () => apiClient('/students/leads');
export const createStudent = (data: any) =>
  apiClient('/students', {
    method: 'POST',
    body: JSON.stringify(data),
  });

export const exportStudents = async (filters = {}) => {
  const queryParams = new URLSearchParams(
    Object.fromEntries(
      Object.entries(filters)
        .filter(([_, v]) => v != null && v !== '' && v !== 'Tất cả')
        .map(([k, v]) => [k, String(v)]),
    ),
  );

  const blob = await apiClient<Blob>(`/students/export?${queryParams.toString()}`, {
    responseType: 'blob',
  });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `danh_sach_hoc_vien_${new Date().getTime()}.xlsx`;
  document.body.appendChild(a);
  a.click();
  window.URL.revokeObjectURL(url);
  document.body.removeChild(a);
};
export const updateStudent = (id: string, data: any) =>
  apiClient(`/students/${id}`, {
    method: 'PUT',
    body: JSON.stringify(data),
  });

export const deleteStudent = (id: string) =>
  apiClient(`/students/${id}`, {
    method: 'DELETE',
  });

export const bulkDeleteStudents = (ids: string[]) =>
  apiClient('/students/bulk', {
    method: 'DELETE',
    body: JSON.stringify({ ids }),
  });

export const getStudentHistory = (id: string, page = 1, limit = 20) => {
  return apiClient(`/students/${id}/history?page=${page}&limit=${limit}`);
};

export const importStudents = async (file: File, importType: string = 'student_only') => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('import_type', importType);

  return apiClient('/students/import', {
    method: 'POST',
    body: formData,
  });
};

export const downloadStudentTemplate = async (importType: string = 'student_only') => {
  const blob = await apiClient<Blob>(`/students/import-template?type=${importType}`, {
    responseType: 'blob',
  });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = importType === 'student_only' ? `mau_nhap_hoc_vien_ahv.xlsx` : `mau_nhap_hoc_vien_va_khoa_ahv.xlsx`;
  document.body.appendChild(a);
  a.click();
  window.URL.revokeObjectURL(url);
  document.body.removeChild(a);
};

